CREATE OR REPLACE FUNCTION fpb_get_count_coll (as_conno char) RETURNS bigint AS $body$
DECLARE

  li_count_coll integer;

BEGIN

    select  count(*)
    into STRICT    li_count_coll
    from    sc_lon_m_contract_coll
    where   loan_contract_no = as_conno 
    and     status <> '1';
    if coalesce(li_count_coll::text, '') = '' then li_count_coll := 1;end if;

  return li_count_coll;
  exception when others then return 1;

end;
$body$
